-- ----------------------------
-- Table structure for city_carbon_gdp
-- ----------------------------
DROP TABLE IF EXISTS `city_carbon_gdp`;
CREATE TABLE `city_carbon_gdp`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '城市名称',
  `province` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '省份名称',
  `city_code` bigint NULL DEFAULT NULL COMMENT '城市代码',
  `year` int NOT NULL COMMENT '年份',
  `gdp` double NULL DEFAULT NULL COMMENT 'GDP（亿元）',
  `gdp_growth` double NULL DEFAULT NULL COMMENT 'GDP增速（%）',
  `per_capita_gdp` double NULL DEFAULT NULL COMMENT '人均GDP（元）',
  `co2_emission` double NULL DEFAULT NULL COMMENT 'CO2排放量（万吨）',
  `carbon_intensity` double NULL DEFAULT NULL COMMENT '碳排放强度（吨/万元）',
  `primary_industry` double NULL DEFAULT NULL COMMENT '第一产业增加值（亿元）',
  `secondary_industry` double NULL DEFAULT NULL COMMENT '第二产业增加值（亿元）',
  `tertiary_industry` double NULL DEFAULT NULL COMMENT '第三产业增加值（亿元）',
  `primary_industry_ratio` double NULL DEFAULT NULL COMMENT '第一产业增加值占GDP比重（%）',
  `secondary_industry_ratio` double NULL DEFAULT NULL COMMENT '第二产业增加值占GDP比重（%）',
  `tertiary_industry_ratio` double NULL DEFAULT NULL COMMENT '第三产业增加值占GDP比重（%）',
  `population` double NULL DEFAULT NULL COMMENT '年末常住人口数（万人）',
  `energy_consumption` double NULL DEFAULT NULL COMMENT '能源消费总量（万吨标准煤）',
  `energy_per_capita` double NULL DEFAULT NULL COMMENT '人均能源消耗（吨标准煤/人）',
  `energy_intensity` double NULL DEFAULT NULL COMMENT '能源消费强度（吨标准煤/万元）',
  `emission_reduction_efficiency` double NULL DEFAULT NULL COMMENT '减排效率',
  `longitude` double NULL DEFAULT NULL COMMENT '经度',
  `latitude` double NULL DEFAULT NULL COMMENT '纬度',
  `yangtze_river_belt` int NULL DEFAULT NULL COMMENT '长江经济带（1是/0否）',
  `carbon_did` int NULL DEFAULT NULL COMMENT '碳排放交易DID',
  `green_finance_did` int NULL DEFAULT NULL COMMENT '绿色金融试点DID',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_city_year`(`city` ASC, `year` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7201 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '市级碳排放和GDP数据表' ROW_FORMAT = DYNAMIC;

